import * as XLSX from 'xlsx';

export const exportToExcel = (data, filename = 'export') => {
  if (!data || !data.length) return;

  let rows;
  if (filename === 'master') {
    rows = data.map((r, i) => ({
      '#': i + 1,
      'Region': r.region,
      'Head Count': parseInt(r.head_count),
      'Birthday Budget/Head (₹)': parseFloat(r.birthday_budget_per_head),
      'Birthday Events': parseInt(r.birthday_events),
      'Festival Budget/Head (₹)': parseFloat(r.festival_budget_per_head),
      'Festival Events': parseInt(r.festival_events),
      'Birthday Amount (₹)': parseFloat(r.birthday_amount),
      'Festival Amount (₹)': parseFloat(r.festival_amount),
      'Total Amount (₹)': parseFloat(r.total_amount),
      'Date Created': r.created_at ? new Date(r.created_at).toLocaleDateString('en-IN') : ''
    }));
  } else {
    rows = data;
  }

  const ws = XLSX.utils.json_to_sheet(rows);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'Sheet1');
  XLSX.writeFile(wb, `${filename}_${new Date().toISOString().slice(0,10)}.xlsx`);
};
